const CDN = 'https://assets.scratch.mit.edu/internalapi/asset/';
const cacheAssets = new Map(); // md5ext -> base64

function normalizar(n) {
  return String(n || '').trim().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

export function buscarPersonajeEnTodo(nombre) {
  const n = normalizar(nombre);
  const hit = CATALOGO_PERSONAJES_TODOS.find(([nom]) => normalizar(nom) === n);
  if (!hit) return null;
  return { nombre: hit[0], disfraces: hit[1].map(([dn, md5ext, rx, ry]) => ({ nombre: dn, md5ext, rc: [rx, ry] })) };
}

export function buscarFondoEnTodo(nombre) {
  const n = normalizar(nombre);
  const hit = CATALOGO_FONDOS_TODOS.find(([nom]) => normalizar(nom) === n);
  if (!hit) return null;
  return { nombre: hit[0], md5ext: hit[1], rc: [hit[2], hit[3]] };
}

// descarga un asset del CDN oficial y lo devuelve en base64 (con cache)
export async function descargarAsset(md5ext) {
  if (cacheAssets.has(md5ext)) return cacheAssets.get(md5ext);
  // un reintento: los cortes momentáneos de red son comunes en las escuelas
  let resp;
  try {
    resp = await fetch(CDN + md5ext + '/get/');
  } catch (e) {
    await new Promise(r => setTimeout(r, 800));
    resp = await fetch(CDN + md5ext + '/get/');
  }
  if (!resp.ok) throw new Error('No se pudo descargar ' + md5ext + ' (' + resp.status + ')');
  const buf = await resp.arrayBuffer();
  let bin = '';
  const bytes = new Uint8Array(buf);
  for (let i = 0; i < bytes.length; i += 0x8000) {
    bin += String.fromCharCode.apply(null, bytes.subarray(i, i + 0x8000));
  }
  const b64 = btoa(bin);
  cacheAssets.set(md5ext, b64);
  return b64;
}

export function urlMiniatura(md5ext) {
  return CDN + md5ext + '/get/';
}
